import { api } from 'lwc';
import LightningOverlay from 'lightning/overlay';
export default class MenuOverlay extends LightningOverlay {
    @api
    items = [];
    handleItemClick(event) {
        const value = event.currentTarget.dataset.value;
        this.close(value);
    }
    handleItemKeyDown(event) {
        const currentItem = event.currentTarget;
        const allItems = Array.from(this.template.querySelectorAll('[role="menuitem"]'));
        const currentIndex = allItems.indexOf(currentItem);
        switch (event.key) {
            case 'Enter':
            case ' ': {
                event.preventDefault();
                const value = currentItem.dataset.value;
                this.close(value);
                break;
            }
            case 'ArrowDown': {
                event.preventDefault();
                const nextIndex = (currentIndex + 1) % allItems.length;
                const nextItem = allItems[nextIndex];
                nextItem.focus();
                break;
            }
            case 'ArrowUp': {
                event.preventDefault();
                const prevIndex = currentIndex === 0 ? allItems.length - 1 : currentIndex - 1;
                const prevItem = allItems[prevIndex];
                prevItem.focus();
                break;
            }
            case 'Home': {
                event.preventDefault();
                allItems[0].focus();
                break;
            }
            case 'End': {
                event.preventDefault();
                allItems[allItems.length - 1].focus();
                break;
            }
            case 'Tab': {
                this.close();
                break;
            }
            default: {
                break;
            }
        }
    }
}
